SELECT count(*) FROM hm_query.recommendations_flat

    AND user_id = #{userId}
    AND recommendation_type = #{recommendationType}
    AND product_id = #{productId}
    AND (product_name LIKE CONCAT('%', #{q}, '%') OR reason LIKE CONCAT('%', #{q}, '%'))

SELECT id AS "id", user_id AS "userId", product_id AS "productId", product_name AS "productName", recommendation_type AS "recommendationType", score AS "score", reason AS "reason", created_time AS "createdTime" FROM hm_query.recommendations_flat
AND user_id = #{userId} AND recommendation_type = #{recommendationType} AND product_id = #{productId} AND (product_name LIKE CONCAT('%', #{q}, '%') OR reason LIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}

SELECT count(*) FROM hm_query.trending_products_flat

    AND category = #{category}
    AND time_window = #{timeWindow}
    AND product_id = #{productId}
    AND product_name LIKE CONCAT('%', #{q}, '%')

SELECT id AS "id", product_id AS "productId", product_name AS "productName", category AS "category", trending_score AS "trendingScore", time_window AS "timeWindow", view_count AS "viewCount", order_count AS "orderCount", created_time AS "createdTime" FROM hm_query.trending_products_flat
AND category = #{category} AND time_window = #{timeWindow} AND product_id = #{productId} AND product_name LIKE CONCAT('%', #{q}, '%')
${orderby} ${pagination}
